public class DEVLicenseLogCleanup extends RunBaseBatch implements BatchRetryable
{
    NoYesId      isDelete;
    Days         keepDays;
    NoYesId      isCompact;

    DialogField  dlgIsDelete;
    DialogField  dlgKeepDays;
    DialogField  dlgIsCompact;


    #define.CurrentVersion(1)
    #localmacro.CurrentList
        isDelete,
        keepDays,
        isCompact
    #endmacro

}

Method.Source:
public Object dialog()
{
    DialogRunbase       dialog = super();
    ;
    dlgIsDelete   = dialog.addFieldValue(extendedtypestr(NoYesId), isDelete, "Delete data", "Delete data from the table");
    dlgKeepDays   = dialog.addFieldValue(extendedtypestr(Days), keepDays, "Days to keep", "Days to keep data");
    dlgIsCompact  = dialog.addFieldValue(extendedtypestr(NoYesId), isCompact, "Compact data", "Delete duplicate data");

    return dialog;
}

public boolean getFromDialog()
{
    ;
    isDelete    = dlgIsDelete.value();
    keepDays    = dlgKeepDays.value();
    isCompact   = dlgIsCompact.value();

    return super();
}

public NoYesId parmIsDelete(NoYesId _isDelete = isDelete)
{
    isDelete = _isDelete;
    return isDelete;
}

public Days parmKeepDays(Days _keepDays = keepDays)
{
    keepDays = _keepDays;
    return keepDays;
}

public NoYesId parmIsCompact(NoYesId _isCompact = isCompact)
{
    isCompact = _isCompact;
    return isCompact;
}

public boolean unpack(container _packedClass)
{
    Version    version = RunBase::getVersion(_packedClass);
    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = _packedClass;
            break;
        default:
            return false;
    }
    return true;
}

    public void run()
    {
        DEVLicenseElementUsageLog		licenseElementUsageLog, licenseElementUsageLogUpd;
        DEVLicenseElementWriteLog       licenseWriteLog, licenseWriteLogUpd;
        int numberOfRecords;
        utcdatetime calcDate = DateTimeUtil::addDays(DateTimeUtil::utcNow(), -1 * keepDays);
		if (isDelete)
        {
            ttsbegin;
            delete_from licenseElementUsageLog
                where licenseElementUsageLog.CreatedDateTime <= calcDate;
            ttscommit;
            info(strFmt("Deleted %1 records from %2", licenseElementUsageLog.RowCount(), calcDate));

            ttsbegin;
            delete_from licenseWriteLog
                where licenseWriteLog.CreatedDateTime <= calcDate;
            ttscommit;
            info(strFmt("Deleted %1 write log records from %2", licenseWriteLog.RowCount(), calcDate));
		}
        if (isCompact)
        {
            while select maxof(RecId) from licenseElementUsageLog
                group by AOTName, SecurableType, UserId, ObjectType, ObjectName, CompanyId
            {
                ttsbegin;
                licenseElementUsageLogUpd = null;
				delete_from licenseElementUsageLogUpd
					where licenseElementUsageLogUpd.RecId         < licenseElementUsageLog.RecId &&
						  licenseElementUsageLogUpd.AOTName       == licenseElementUsageLog.AOTName &&
						  licenseElementUsageLogUpd.SecurableType == licenseElementUsageLog.SecurableType &&
						  licenseElementUsageLogUpd.UserId        == licenseElementUsageLog.UserId &&
						  licenseElementUsageLogUpd.ObjectType    == licenseElementUsageLog.ObjectType &&
						  licenseElementUsageLogUpd.ObjectName    == licenseElementUsageLog.ObjectName &&
                          licenseElementUsageLogUpd.CompanyId     == licenseElementUsageLog.CompanyId;

                numberOfRecords += licenseElementUsageLogUpd.RowCount();
                ttscommit;
			}
            info(strFmt("Compacted %1 records ", numberOfRecords));

            numberOfRecords = 0;
            while select maxof(RecId) from licenseWriteLog
                group by AOTName, SecurableType, UserId, ObjectType, ObjectName, CompanyId, TableName
            {
                ttsbegin;
                licenseWriteLogUpd = null;
                delete_from licenseWriteLogUpd
                    where licenseWriteLogUpd.RecId         < licenseWriteLog.RecId &&
                          licenseWriteLogUpd.AOTName       == licenseWriteLog.AOTName  &&
                          licenseWriteLogUpd.SecurableType == licenseWriteLog.SecurableType &&
                          licenseWriteLogUpd.UserId        == licenseWriteLog.UserId &&
                          licenseWriteLogUpd.ObjectType    == licenseWriteLog.ObjectType &&
                          licenseWriteLogUpd.ObjectName    == licenseWriteLog.ObjectName &&
                          licenseWriteLogUpd.CompanyId     == licenseWriteLog.CompanyId  &&
                          licenseWriteLogUpd.TableName     == licenseWriteLog.TableName;

                numberOfRecords += licenseWriteLogUpd.RowCount();
                ttscommit;
            }
            info(strFmt("Compacted %1 write log records", numberOfRecords));
		}

    }

public static DEVLicenseLogCleanup construct()
{
    return new DEVLicenseLogCleanup();
}

static ClassDescription description()
{
    return "Cleanup element usage log";
}

public static void main(Args _args)
{
    DEVLicenseLogCleanup    runObject = DEVLicenseLogCleanup::construct();
    ;
    if (runObject.prompt())
    {
        runObject.runOperation();
    }
}
